  it('runs bun test', () => {
    const content = readFileSync(WORKFLOW_PATH, 'utf-8');
    expect(content).toContain('bun test');
  });

  it('references main.ts which exists', () => {
    expect(existsSync(join(PROJECT_DIR, 'main.ts'))).toBe(true);
